<?php
namespace App\Domain\Hunts\Rewards;
use App\Domain\Hunts\Rewards\Data\HuntRewardValues;use App\Domain\Random\RandomNumberGenerator;
final class HuntRewardValueGenerator{private $random;public function __construct(RandomNumberGenerator $random){$this->random=$random;}public function generate($enemies,$monsters):HuntRewardValues{$gold=0;$experience=0;foreach($enemies->sortBy('position') as $enemy){$monster=$monsters->get($enemy->monster_id);if(!$monster)throw new \InvalidArgumentException('Monster catalog missing.');$minimum=$this->safe($monster->gold_min);$maximum=$this->safe($monster->gold_max);$rewardExperience=$this->safe($monster->experience_reward);if($minimum>$maximum)throw new \InvalidArgumentException('Invalid Monster gold range.');$rolled=$minimum===$maximum?$minimum:$this->random->randomInt($minimum,$maximum);if($rolled>PHP_INT_MAX-$gold||$rewardExperience>PHP_INT_MAX-$experience)throw new \InvalidArgumentException('Reward value overflow.');$gold+=$rolled;$experience+=$rewardExperience;}return new HuntRewardValues($gold,$experience);}private function safe($value):int{if(is_int($value)&&$value>=0)return$value;if(is_string($value)&&preg_match('/^(0|[1-9][0-9]*)$/',$value)&&(strlen($value)<strlen((string)PHP_INT_MAX)||(strlen($value)===strlen((string)PHP_INT_MAX)&&strcmp($value,(string)PHP_INT_MAX)<=0)))return(int)$value;throw new \InvalidArgumentException('Reward value exceeds the safe PHP integer range.');}}
